// src/views/EmployeeEvaluation.js
import React, { useState, useEffect } from "react";
import { useParams, useLocation, useHistory } from "react-router-dom";
import Footer from "components/Footers/Footer.js";
import Navbar from "components/Navbars/AuthNavbar.js";
import SocialFooter from "components/Common/socialFooter";

export default function EmployeeEvaluation() {
  const { id } = useParams();
  const location = useLocation();
  const history = useHistory();
  const employeeFromList = location.state?.employee || null;
  
  const [employee, setEmployee] = useState(null);
  const [loading, setLoading] = useState(true);
  const [workHistory, setWorkHistory] = useState([]);
  const [workerStatus, setWorkerStatus] = useState("working");
  const [currentWorkPlace, setCurrentWorkPlace] = useState(null);
  const [showEvaluationForm, setShowEvaluationForm] = useState(false);
  const [currentRating, setCurrentRating] = useState(0);
  const [managerComment, setManagerComment] = useState("");
  const [isSubmitting, setIsSubmitting] = useState(false);
  
  // قائمة أماكن العمل المتاحة
  const availablePlaces = [
    { id: 1, name: "Restaurant Andalous", icon: "🏪" },
    { id: 2, name: "Café Parisien", icon: "☕" },
    { id: 3, name: "La Piazza Italia", icon: "🍕" },
    { id: 4, name: "Sushi Master", icon: "🍣" },
    { id: 5, name: "Le Gourmet", icon: "🍽️" }
  ];
  
  // بيانات الموظفين
  const employeesData = {
    1: {
      id: 1,
      name: "Youssef",
      role: "Employé",
      profileImage: "https://randomuser.me/api/portraits/men/1.jpg",
      coverImage: "https://images.unsplash.com/photo-1517248135467-4c7edcad34c4",
      location: "Casablanca, Maroc",
      email: "youssef@example.com",
      phone: "+212 6 12 34 56 78",
      skills: ["Service client", "Rapidité", "Polyvalence"],
      bio: "Employé dévoué avec 3 ans d'expérience dans la restauration.",
      status: "working",
      currentPlace: { id: 1, name: "Restaurant Andalous", icon: "🏪" }
    },
    2: {
      id: 2,
      name: "Mohamed",
      role: "Employé",
      profileImage: "https://randomuser.me/api/portraits/men/2.jpg",
      coverImage: "https://images.unsplash.com/photo-1517248135467-4c7edcad34c4",
      location: "Rabat, Maroc",
      email: "mohamed@example.com",
      phone: "+212 6 98 76 54 32",
      skills: ["Gestion des stocks", "Organisation", "Travail d'équipe"],
      bio: "Employé sérieux et organisé, spécialisé dans la gestion des stocks.",
      status: "working",
      currentPlace: { id: 2, name: "Café Parisien", icon: "☕" }
    }
  };
  
  // بيانات التقييمات
  const mockWorkHistory = {
    1: [
      { id: 1, place: "Restaurant Andalous", role: "Employé", duration: "15/01/2024", rating: 5, review: "Excellent employé, très professionnel !", manager: "Ahmed Benali" },
      { id: 2, place: "Café Central", role: "Stagiaire", duration: "01/10/2023", rating: 4, review: "Bon travail, à encouragé.", manager: "Karim El Fassi" }
    ],
    2: [
      { id: 1, place: "Café Parisien", role: "Employé", duration: "01/02/2024", rating: 4, review: "Travail correct, ponctuel.", manager: "Sophie Martin" }
    ]
  };
  
  useEffect(() => {
    try {
      if (employeeFromList && employeeFromList.id) {
        setEmployee(employeeFromList);
        setWorkHistory(mockWorkHistory[employeeFromList.id] || []);
        setWorkerStatus(employeeFromList.status || "working");
        setCurrentWorkPlace(employeeFromList.currentPlace || availablePlaces[0]);
        setLoading(false);
      } 
      else if (id && employeesData[id]) {
        setEmployee(employeesData[id]);
        setWorkHistory(mockWorkHistory[id] || []);
        setWorkerStatus(employeesData[id].status || "working");
        setCurrentWorkPlace(employeesData[id].currentPlace || availablePlaces[0]);
        setLoading(false);
      } 
      else {
        setEmployee(employeesData[1]);
        setWorkHistory(mockWorkHistory[1] || []);
        setWorkerStatus("working");
        setCurrentWorkPlace(availablePlaces[0]);
        setLoading(false);
      }
    } catch (error) {
      console.error("Error:", error);
      setLoading(false);
    }
  }, [id, employeeFromList]);
  
  const handleAddEvaluation = () => {
    if (currentRating === 0) {
      alert("⚠️ Veuillez sélectionner une note");
      return;
    }
    
    if (!managerComment.trim()) {
      alert("⚠️ Veuillez ajouter un commentaire");
      return;
    }
    
    setIsSubmitting(true);
    
    const newEvaluation = {
      id: Date.now(),
      place: currentWorkPlace?.name || "Lieu inconnu",
      role: employee?.role || "Employé",
      duration: new Date().toLocaleDateString('fr-FR'),
      rating: currentRating,
      review: managerComment.trim(),
      manager: "Ahmed Benali"
    };
    
    setWorkHistory([newEvaluation, ...workHistory]);
    setCurrentRating(0);
    setManagerComment("");
    setShowEvaluationForm(false);
    setIsSubmitting(false);
    alert("✅ Évaluation ajoutée avec succès !");
  };
  
  const handleStatusChange = () => {
    const newStatus = workerStatus === "working" ? "free" : "working";
    setWorkerStatus(newStatus);
    alert(`✅ Statut mis à jour : ${newStatus === 'working' ? 'En poste' : 'En recherche'}`);
  };
  
  const handleWorkPlaceChange = (place) => {
    setCurrentWorkPlace(place);
    alert(`✅ Lieu de travail changé : ${place.name}`);
  };
  
  const style = `
    .employee-page {
      min-height: 100vh;
      background: #0a0a0a;
      padding-top: 80px;
    }
    
    .page-container {
      max-width: 1200px;
      margin: 0 auto;
      padding: 20px;
    }
    
    .back-btn {
      background: rgba(255,255,255,0.1);
      border: 1px solid rgba(34,197,94,0.3);
      border-radius: 30px;
      padding: 10px 20px;
      color: white;
      cursor: pointer;
      display: inline-flex;
      align-items: center;
      gap: 8px;
      transition: all 0.3s;
      margin-bottom: 20px;
    }
    
    .back-btn:hover {
      background: rgba(34,197,94,0.2);
      transform: translateX(-3px);
    }
    
    .profile-card {
      background: rgba(255,255,255,0.08);
      backdrop-filter: blur(10px);
      border-radius: 30px;
      overflow: hidden;
      border: 1px solid rgba(34,197,94,0.2);
      margin-bottom: 30px;
    }
    
    .cover-image {
      height: 200px;
      background-size: cover;
      background-position: center;
      position: relative;
    }
    
    .profile-header {
      display: flex;
      flex-direction: column;
      align-items: center;
      margin-top: -60px;
      padding: 0 20px;
    }
    
    .profile-avatar {
      width: 120px;
      height: 120px;
      border-radius: 50%;
      border: 4px solid #22c55e;
      object-fit: cover;
      background: #1a1a3a;
    }
    
    .profile-name {
      font-size: 28px;
      font-weight: bold;
      color: white;
      margin-top: 15px;
    }
    
    .profile-role {
      color: #22c55e;
      font-size: 16px;
      margin-top: 5px;
    }
    
    .profile-location {
      color: rgba(255,255,255,0.6);
      font-size: 14px;
      margin-top: 5px;
    }
    
    .profile-bio {
      color: rgba(255,255,255,0.7);
      text-align: center;
      padding: 20px;
      font-style: italic;
    }
    
    .skills-container {
      display: flex;
      flex-wrap: wrap;
      justify-content: center;
      gap: 10px;
      padding: 0 20px 20px;
    }
    
    .skill-tag {
      background: rgba(34,197,94,0.2);
      border: 1px solid rgba(34,197,94,0.3);
      border-radius: 20px;
      padding: 5px 12px;
      font-size: 12px;
      color: #4ade80;
    }
    
    .info-card {
      background: rgba(255,255,255,0.05);
      border-radius: 20px;
      padding: 20px;
      margin-bottom: 20px;
    }
    
    .info-title {
      font-size: 18px;
      font-weight: bold;
      color: white;
      margin-bottom: 15px;
      display: flex;
      align-items: center;
      gap: 10px;
      border-bottom: 1px solid rgba(255,255,255,0.1);
      padding-bottom: 10px;
    }
    
    .status-badge {
      display: inline-block;
      padding: 5px 12px;
      border-radius: 20px;
      font-size: 12px;
      font-weight: bold;
      background: #22c55e;
      color: white;
    }
    
    .status-badge.free {
      background: #f59e0b;
    }
    
    .btn-success {
      background: linear-gradient(135deg, #22c55e, #15803d);
      border: none;
      padding: 10px 20px;
      border-radius: 25px;
      color: white;
      font-weight: bold;
      cursor: pointer;
      transition: all 0.2s;
    }
    
    .btn-danger {
      background: linear-gradient(135deg, #ef4444, #b91c1c);
      border: none;
      padding: 10px 20px;
      border-radius: 25px;
      color: white;
      font-weight: bold;
      cursor: pointer;
      transition: all 0.2s;
    }
    
    .btn-outline {
      background: transparent;
      border: 1px solid rgba(34,197,94,0.5);
      padding: 10px 20px;
      border-radius: 25px;
      color: white;
      font-weight: bold;
      cursor: pointer;
      transition: all 0.2s;
    }
    
    .btn-outline:hover {
      background: rgba(34,197,94,0.2);
    }
    
    .btn-success:hover, .btn-danger:hover, .btn-outline:hover {
      transform: scale(1.02);
    }
    
    .place-selector {
      display: grid;
      grid-template-columns: repeat(auto-fit, minmax(150px, 1fr));
      gap: 10px;
      margin-top: 15px;
    }
    
    .place-option {
      background: rgba(34,197,94,0.1);
      border: 1px solid rgba(34,197,94,0.3);
      border-radius: 15px;
      padding: 12px;
      text-align: center;
      cursor: pointer;
      transition: all 0.2s;
    }
    
    .place-option:hover {
      background: rgba(34,197,94,0.2);
      transform: scale(1.02);
    }
    
    .place-icon {
      font-size: 24px;
    }
    
    .place-name {
      color: white;
      font-size: 12px;
      margin-top: 5px;
    }
    
    .rating-stars {
      display: flex;
      gap: 10px;
      justify-content: center;
      margin: 15px 0;
    }
    
    .rating-star {
      font-size: 30px;
      cursor: pointer;
      color: #4a4a4a;
      transition: all 0.2s;
    }
    
    .rating-star:hover {
      transform: scale(1.1);
    }
    
    .rating-star.active {
      color: #ffc107;
    }
    
    .comment-input {
      width: 100%;
      padding: 12px;
      background: rgba(255,255,255,0.1);
      border: 1px solid rgba(34,197,94,0.3);
      border-radius: 15px;
      color: white;
      resize: vertical;
      font-family: inherit;
    }
    
    .comment-input:focus {
      outline: none;
      border-color: #22c55e;
    }
    
    .evaluation-item {
      background: rgba(255,255,255,0.05);
      border-radius: 15px;
      padding: 15px;
      margin-bottom: 15px;
      border-left: 3px solid #22c55e;
    }
    
    .evaluation-header {
      display: flex;
      justify-content: space-between;
      align-items: center;
      flex-wrap: wrap;
      margin-bottom: 8px;
    }
    
    .evaluation-place {
      font-weight: bold;
      color: white;
    }
    
    .evaluation-stars {
      display: flex;
      gap: 3px;
    }
    
    .evaluation-star {
      font-size: 14px;
      color: #ffc107;
    }
    
    .evaluation-star.inactive {
      color: #4a4a4a;
    }
    
    .evaluation-details {
      color: rgba(255,255,255,0.5);
      font-size: 12px;
      margin-bottom: 8px;
    }
    
    .evaluation-review {
      color: rgba(255,255,255,0.8);
      font-size: 14px;
      font-style: italic;
    }
    
    .button-group {
      display: flex;
      gap: 10px;
      flex-wrap: wrap;
      margin-top: 15px;
    }
    
    @media (max-width: 768px) {
      .profile-avatar {
        width: 100px;
        height: 100px;
      }
      
      .profile-name {
        font-size: 22px;
      }
      
      .place-selector {
        grid-template-columns: repeat(2, 1fr);
      }
      
      .rating-star {
        font-size: 25px;
      }
    }
  `;

  if (loading) {
    return (
      <>
        <style>{style}</style>
        <Navbar />
        <div className="employee-page" style={{ display: "flex", alignItems: "center", justifyContent: "center" }}>
          <div style={{ textAlign: "center", color: "white" }}>
            <div style={{ width: "50px", height: "50px", border: "3px solid rgba(255,255,255,0.2)", borderTopColor: "#22c55e", borderRadius: "50%", animation: "spin 1s linear infinite", margin: "0 auto 20px" }}></div>
            <p>Chargement...</p>
          </div>
          <style>{`@keyframes spin { to { transform: rotate(360deg); } }`}</style>
        </div>
        <Footer />
      </>
    );
  }

  if (!employee) {
    return (
      <>
        <style>{style}</style>
        <Navbar />
        <div className="employee-page" style={{ display: "flex", alignItems: "center", justifyContent: "center" }}>
          <div style={{ textAlign: "center", color: "white" }}>
            <h2>👨‍🍳 Employé non trouvé</h2>
            <button onClick={() => history.push("/manager")} className="btn-success" style={{ marginTop: "20px" }}>Retour</button>
          </div>
        </div>
        <Footer />
      </>
    );
  }

  return (
    <>
      <style>{style}</style>
      <Navbar />
      
      <div className="employee-page">
        <div className="page-container">
          
          <button className="back-btn" onClick={() => history.push("/manager")}>
            ← Retour à la liste
          </button>
          
          {/* Profil Card */}
          <div className="profile-card">
            <div className="cover-image" style={{ backgroundImage: `url(${employee.coverImage})` }}></div>
            
            <div className="profile-header">
              <img src={employee.profileImage} alt={employee.name} className="profile-avatar" />
              <h1 className="profile-name">{employee.name}</h1>
              <p className="profile-role">{employee.role}</p>
              <p className="profile-location">📍 {employee.location}</p>
              <span className={`status-badge ${workerStatus === "free" ? "free" : ""}`}>
                {workerStatus === "working" ? "✅ En poste" : "📢 En recherche"}
              </span>
            </div>
            
            <p className="profile-bio">"{employee.bio}"</p>
            
            <div className="skills-container">
              {employee.skills?.map((skill, i) => (
                <span key={i} className="skill-tag">{skill}</span>
              ))}
            </div>
          </div>
          
          {/* Informations de contact */}
          <div className="info-card">
            <div className="info-title">
              <span>📞</span> Contact
            </div>
            <p style={{ color: "rgba(255,255,255,0.7)", marginBottom: "5px" }}>📧 {employee.email}</p>
            <p style={{ color: "rgba(255,255,255,0.7)" }}>📱 {employee.phone}</p>
          </div>
          
          {/* Gestion du statut et lieu de travail */}
          <div className="info-card">
            <div className="info-title">
              <span>⚙️</span> Gestion
            </div>
            
            <div style={{ marginBottom: "20px" }}>
              <p style={{ color: "white", marginBottom: "10px" }}>
                📍 Lieu actuel: <strong style={{ color: "#22c55e" }}>{currentWorkPlace?.name || "Non défini"}</strong>
              </p>
              
              <div className="button-group">
                <button className="btn-outline" onClick={() => setShowEvaluationForm(!showEvaluationForm)}>
                  {showEvaluationForm ? "🙈 Masquer" : "✏️ Ajouter une évaluation"}
                </button>
                <button className="btn-outline" onClick={handleStatusChange}>
                  {workerStatus === "working" ? "🚫 Marquer comme libre" : "✅ Marquer comme actif"}
                </button>
              </div>
            </div>
            
            {showEvaluationForm && (
              <div style={{ marginTop: "20px", borderTop: "1px solid rgba(255,255,255,0.1)", paddingTop: "20px" }}>
                <h4 style={{ color: "white", marginBottom: "15px" }}>📝 Nouvelle évaluation</h4>
                
                <div className="rating-stars">
                  {[1,2,3,4,5].map(star => (
                    <span 
                      key={star} 
                      className={`rating-star ${currentRating >= star ? "active" : ""}`}
                      onClick={() => setCurrentRating(star)}
                    >★</span>
                  ))}
                </div>
                
                <textarea 
                  className="comment-input"
                  rows="3"
                  placeholder="Écrivez votre commentaire..."
                  value={managerComment}
                  onChange={(e) => setManagerComment(e.target.value)}
                ></textarea>
                
                <button 
                  className="btn-success" 
                  style={{ width: "100%", marginTop: "15px" }}
                  onClick={handleAddEvaluation}
                  disabled={isSubmitting}
                >
                  {isSubmitting ? "Envoi..." : "✅ Ajouter l'évaluation"}
                </button>
              </div>
            )}
          </div>
          
          {/* Changement de lieu de travail */}
          <div className="info-card">
            <div className="info-title">
              <span>🏪</span> Changer le lieu de travail
            </div>
            
            <div className="place-selector">
              {availablePlaces.map(place => (
                <div key={place.id} className="place-option" onClick={() => handleWorkPlaceChange(place)}>
                  <div className="place-icon">{place.icon}</div>
                  <div className="place-name">{place.name}</div>
                </div>
              ))}
            </div>
          </div>
          
          {/* Historique des évaluations */}
          <div className="info-card">
            <div className="info-title">
              <span>📋</span> Historique des évaluations ({workHistory.length})
            </div>
            
            {workHistory.length > 0 ? (
              workHistory.map(evalItem => (
                <div key={evalItem.id} className="evaluation-item">
                  <div className="evaluation-header">
                    <span className="evaluation-place">{evalItem.place}</span>
                    <div className="evaluation-stars">
                      {[1,2,3,4,5].map(star => (
                        <span key={star} className={`evaluation-star ${star <= evalItem.rating ? "" : "inactive"}`}>★</span>
                      ))}
                    </div>
                  </div>
                  <div className="evaluation-details">
                    {evalItem.role} • {evalItem.duration} • Manager: {evalItem.manager}
                  </div>
                  <div className="evaluation-review">"{evalItem.review}"</div>
                </div>
              ))
            ) : (
              <p style={{ textAlign: "center", color: "rgba(255,255,255,0.5)", padding: "20px" }}>
                Aucune évaluation pour le moment
              </p>
            )}
          </div>
          
        </div>
      </div>
      
      <SocialFooter socialLinks={{}} />
      <Footer />
    </>
  );
}
